import{_ as e,c as t,o as l,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"快速上手 AI App Factory：從安裝到運行第一個應用 | agent-app-factory","description":"學習如何快速啟動 AI App Factory，從安裝配置 CLI 工具到理解 7 階段流水線的工作原理，掌握初始化專案並開始你的第一個應用生成之旅。本章節包含快速開始、安裝配置、專案初始化和流水線概覽四個核心課程，幫助你全面了解從想法到可運行應用的端到端自動化流程。","frontmatter":{"title":"快速上手 AI App Factory：從安裝到運行第一個應用 | agent-app-factory","sidebarTitle":"上手","subtitle":"上手","description":"學習如何快速啟動 AI App Factory，從安裝配置 CLI 工具到理解 7 階段流水線的工作原理，掌握初始化專案並開始你的第一個應用生成之旅。本章節包含快速開始、安裝配置、專案初始化和流水線概覽四個核心課程，幫助你全面了解從想法到可運行應用的端到端自動化流程。","order":10},"headers":[],"relativePath":"zh-tw/hyz1992/agent-app-factory/start/index.md","filePath":"zh-tw/hyz1992/agent-app-factory/start/index.md"}'),i={name:"zh-tw/hyz1992/agent-app-factory/start/index.md"};function o(n,a,p,d,s,c){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="上手" tabindex="-1">上手 <a class="header-anchor" href="#上手" aria-label="Permalink to &quot;上手&quot;">​</a></h1><p>本章節幫助你快速上手 AI App Factory，了解核心價值、安裝配置工具，並理解 7 階段流水線的工作原理，為生成第一個應用做好準備。</p><h2 id="學習路徑" tabindex="-1">學習路徑 <a class="header-anchor" href="#學習路徑" aria-label="Permalink to &quot;學習路徑&quot;">​</a></h2><p>建議按照以下順序學習本章節內容：</p><h3 id="_1-快速開始-從想法到應用" tabindex="-1">1. <a href="./../getting-started/">快速開始：從想法到應用</a> <a class="header-anchor" href="#_1-快速開始-從想法到應用" aria-label="Permalink to &quot;1. [快速開始：從想法到應用](../getting-started/)&quot;">​</a></h3><p>了解 AI App Factory 的核心價值和前置要求，透過一個完整的案例體驗從想法到應用的端到端流程。</p><ul><li>理解基於檢查點的多 Agent 協作機制</li><li>了解 7 階段流水線的完整工作流程</li><li>掌握提供清晰產品描述的技巧</li></ul><h3 id="_2-安裝與配置" tabindex="-1">2. <a href="./../installation/">安裝與配置</a> <a class="header-anchor" href="#_2-安裝與配置" aria-label="Permalink to &quot;2. [安裝與配置](../installation/)&quot;">​</a></h3><p>全域安裝 CLI 工具，配置 AI 助手（Claude Code/OpenCode）及相關環境。</p><ul><li>使用 npm 全域安裝 agent-app-factory</li><li>配置 Claude Code 或 OpenCode</li><li>驗證安裝是否成功</li></ul><h3 id="_3-初始化-factory-專案" tabindex="-1">3. <a href="./../init-project/">初始化 Factory 專案</a> <a class="header-anchor" href="#_3-初始化-factory-專案" aria-label="Permalink to &quot;3. [初始化 Factory 專案](../init-project/)&quot;">​</a></h3><p>使用 <code>factory init</code> 命令初始化目錄，了解生成的專案結構和配置檔案。</p><ul><li>執行專案初始化命令</li><li>理解專案目錄結構和配置檔案</li><li>準備產品想法輸入</li></ul><h3 id="_4-7-階段流水線概覽" tabindex="-1">4. <a href="./../pipeline-overview/">7 階段流水線概覽</a> <a class="header-anchor" href="#_4-7-階段流水線概覽" aria-label="Permalink to &quot;4. [7 階段流水線概覽](../pipeline-overview/)&quot;">​</a></h3><p>深入理解從 Bootstrap 到 Preview 的完整流水線流程，各階段的輸入輸出和檢查點機制。</p><ul><li>理解 7 個階段的目標和產物</li><li>掌握檢查點機制和人工確認流程</li><li>學習如何控制流水線執行</li></ul><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><p>開始本章節學習前，你需要：</p><div class="warning custom-block"><p class="custom-block-title">前置要求</p><ol><li><strong>Node.js 環境</strong>：已安裝 Node.js v18 或更高版本</li><li><strong>AI 程式設計助手</strong>：必須配置以下工具之一 <ul><li><a href="https://claude.ai/code" target="_blank" rel="noreferrer">Claude Code</a>（推薦）⭐</li><li><a href="https://opencode.design/" target="_blank" rel="noreferrer">OpenCode</a> 或其他支援 Agent 模式的 AI 助手</li></ul></li><li><strong>基礎命令列操作</strong>：能夠使用終端執行命令</li></ol></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章節學習後，你將掌握：</p><ul><li>✅ AI App Factory 的核心工作原理</li><li>✅ CLI 工具的安裝和配置</li><li>✅ 專案初始化和結構理解</li><li>✅ 7 階段流水線的完整流程</li></ul><p>接下來，建議學習 <strong><a href="./../../platforms/">平台與整合</a></strong> 章節，了解如何在不同的 AI 助手（Claude Code、OpenCode 等）上運行流水線。</p>',23)])])}const f=e(i,[["render",o]]);export{u as __pageData,f as default};
